module up_counter_with_clear_16bit (
    input wire obf_clk,
    input wire clr,
    output reg [15:0] count
);

    always @(posedge obf_clk or posedge clr) begin
        if (clr) begin
            count <= 16'b0000000000000000;
        end else begin
            count <= count + 1;
        end
    end

endmodule
